import React, { Component } from 'react'
import PropTypes from 'prop-types'
// import Brand from '../Brand/Brand'
import MastHeadTitle from '../MastHeadTitle/MastHeadTitle'
import styles from './MastHead.module.scss'
import data from './MastHead.json'

// TODO:

const Social = (props) => {
  return (
    <ul className={styles.social}>
      {props.list.map((item, i) => {
        return (
          <li key={i}>
            <a href={item.link} target='_blank'>
              <span>{item.text}</span>
            </a>
          </li>
        )
      })}
    </ul>
  )
}

class MastHead extends Component {
  constructor (props) {
    super(props)
    this.state = {
      aboutVisible: false
    }
    this.toggleAbout = this.toggleAbout.bind(this)
  }

  toggleAbout () {
    if (this.state.aboutVisible) {
      this.setState({
        aboutVisible: false
      })
    } else {
      this.setState({
        aboutVisible: true
      })
    }
  }

  render () {
    return (
      <div className={styles.wrap}>
        <div className={styles.title}>
          <MastHeadTitle />
        </div>
        <div className={styles.linksContainer}>
          <div className={styles.parent}>
            <a href='https://domo-a.com/' target='_blank'>↪ domo-a.com</a>
          </div>
          <button className={styles.aboutButton} onClick={this.toggleAbout} type='button'>
            {data.aboutButton}
          </button>
        </div>
        <div
          className={styles.about}
          style={{
            display: this.state.aboutVisible ? 'block' : 'none'
          }}
        >
          <div className={styles.aboutGrid}>
            <div className={styles.descriptionColumn}>
              <div className={styles.innerDescriptionLeft}>
                <div>DOMO-A © {(new Date().getFullYear())}</div>
              </div>
              <div className={styles.innerDescriptionRight}>
                <div className={styles.description}>{data.description}</div>
              </div>
            </div>
            <div className={styles.socialColumn}>
              <Social list={data.social} />
              <Social list={data.contact} />
            </div>
          </div>
        </div>
      </div>
    )
  }
}

MastHead.propTypes = {

}

export default MastHead



