import React, { Component } from 'react'
import PropTypes from 'prop-types'
import Swiper from 'react-id-swiper'
import Sticky from 'react-stickynode'
import { animateScroll } from 'react-scroll'
import Purchase from '../Purchase/Purchase'
import styles from './Project.module.scss'
import 'react-id-swiper/src/styles/css/swiper.css'
import './custom.scss'

// TODO: posar els números més avall per a que no molesti el cursor de la fletxa
// https://www.sachamaric.com/books

const swiperConfig = {
  loop: true,
  autoHeight: true,
  spaceBetween: 2,
  navigation: {
    nextEl: '.swiper-next-overlay'
  },
  pagination: {
    el: '.swiper-custom-pagination',
    clickable: true,
    renderBullet: function (index, className) {
      return `<span class="${className}">${index + 1}</span>`
    }
  }
}

const Gallery = (props) => {
  const images = (
    props.gallery.map((data, i) => {
      return (
        <div className={styles.image} key={i}>
          <img srcSet={data.srcSet} sizes={data.sizes} src={data.src} />
          <div className={styles.sizer} />
        </div>
      )
    })
  )
  const slider = (
    <div className={styles.slider}>
      <Swiper {...swiperConfig}>{images}</Swiper>
    </div>
  )
  let el = null
  if (props.gallery.length > 1) {
    el = slider
  } else {
    el = <div className={styles.single}>{images}</div>
  }
  return (
    <div>{el}</div>
  )
}

class Project extends Component {
  constructor (props) {
    super(props)
    this.handleClick = this.handleClick.bind(this)
  }

  handleClick () {
    animateScroll.scrollTo(this.wrap.offsetTop - 30)
  }

  render () {
    const id = this.props.node.slugs[0].replace(/[^\w\s]/gi, '')
    const data = this.props.node.data
    const gallery = this.props.node.fields.galleryImages
    const title = data.title[0].text
    let purchase = null
    let price = null
    if (data.price) {
      price = data.price
    }
    if (data.availability && data.availability === 'Available') {
      purchase = (
        <div className={styles.purchase}>
          <Purchase title={title} price={price} />
        </div>
      )
    }
    return (
      <div className={styles.wrap} name={id} id={id} ref={(el) => { this.wrap = el }} onClick={this.handleClick}>
        <div className={styles.grid}>
          <div className={styles.imageColumn}>
            <Gallery gallery={this.props.gallery} />
          </div>
          <div className={styles.infoColumn}>
            <Sticky top={30} bottomBoundary={`#${id}`}>
              <h2 className={styles.title}>{title}</h2>
              <div className={styles.typology}>— {data.typology}</div>
              <ul className={styles.technical}>
                {data.technical_info.map((field, i) => {
                  return (
                    <li key={i}>{field.info_field}</li>
                  )
                })}
              </ul>
              {purchase}
              <div className={styles.description}>
                {data.description.map((item, i) => {
                  if (item.type === 'paragraph') {
                    return (
                      <p key={i}>{item.text}</p>
                    )
                  }
                })}
              </div>
            </Sticky>
          </div>
        </div>
      </div>
    )
  }
}

/*
Sold out:
purchase = (
  <div className={styles.purchase}>
    <p className={styles.soldout}>Sold out.</p>
  </div>
)
*/

Project.propTypes = {
  node: PropTypes.object.isRequired,
  gallery: PropTypes.array.isRequired
}

export default Project



