import React, { Component } from 'react'
import Sticky from 'react-stickynode'
import Brand from '../components/Brand/Brand'
import Nav from '../components/Nav/Nav'
import MastHead from '../components/MastHead/MastHead'
import Project from '../components/Project/Project'
import styles from '../styles/pages/IndexPage.module.scss'

class IndexPage extends Component {
  render () {
    const navItems = this.props.data.allPrismicDocument.edges.map(({node}) => {
      let item = {}
      item.slug = node.slugs[0].replace(/[^\w\s]/gi, '')
      item.title = node.data.title[0].text
      return item
    })
    return (
      <div className={styles.grid}>
        <div className={styles.navColumn}>
          <Sticky top={30} bottomBoundary='#content'>
            <Brand />
            <Nav items={navItems} />
          </Sticky>
        </div>
        <div className={styles.mainColumn}>
          <MastHead />
          {this.props.data.allPrismicDocument.edges.map(({node}) => {
            const galleryData = node.fields.galleryImages
            const gallery = galleryData.map(({id}, i) => {
              const imgEdge = this.props.data.allImageSharp.edges.find(({node}) => {
                return node.parent.id === id
              })
              return imgEdge.node.sizes
            })
            return (
              <Project key={node.id} node={node} gallery={gallery} />
            )
          })}
        </div>
      </div>
    )
  }
}

export const query = graphql`
  query projectsQuery {
    allPrismicDocument(
      sort: { order: DESC, fields: [data___date]}
    ) {
      edges {
        node {
          id
          slugs
          last_publication_date
          data {
            date
            title {
              text
            }
            technical_info {
              info_field
            }
            description {
              type
              text
            }
            typology
            availability
            price
          }
          fields {
            galleryImages {
              id
            }
          }
        }
      }
    }
    allImageSharp {
      edges {
        node {
          id
          parent {
            id
          }
          sizes(maxWidth: 1100, quality: 80) {
            ...GatsbyImageSharpSizes_withWebp_noBase64
          }
        }
      }
    }
  }
`

export default IndexPage



