import React, { Component } from 'react'
import PropTypes from 'prop-types'
import styles from './PurchaseSuccess.module.scss'

class PurchaseSuccess extends Component {
  render () {
    const title = this.props.error ? `Error` : `Thank you`
    const message = this.props.error ?
                    `Something went wrong, please close this dialog and try again.` :
                    `Thank you ${this.props.name} for showing interest in ${this.props.title}, soon we’ll send an email to “${this.props.email}” with more details.`
    return (
      <div className={styles.wrap}>
        <div className={styles.container}>
          <h1 className={styles.title}>{title}</h1>
          <p className={styles.message}>{message}</p>
        </div>
      </div>
    )
  }
}

PurchaseSuccess.propTypes = {
  message: PropTypes.string
}

export default PurchaseSuccess



