import React, { Component } from 'react'
import PropTypes from 'prop-types'
import PurchaseSuccess from '../PurchaseSuccess/PurchaseSuccess'
import styles from './PurchaseForm.module.scss'
import data from './PurchaseForm.json'

// TODO: pàgina “thank you”, allà es pot posar el form. de subscripció al newsletter
// TODO: de pas revisar els missatges del mailchimp quan et subscrius a una llista

// https://www.netlify.com/blog/2017/07/20/how-to-integrate-netlifys-form-handling-in-a-react-app/
const encode = (data) => {
  return Object.keys(data)
    .map(key => encodeURIComponent(key) + '=' + encodeURIComponent(data[key]))
    .join('&')
}

class PurchaseForm extends Component {
  constructor (props) {
    super(props)
    this.state = {
      project: this.props.title,
      name: '',
      email: '',
      comments: ''
    }
    this.handleSubmit = this.handleSubmit.bind(this)
    this.handleChange = this.handleChange.bind(this)
  }

  handleSubmit (e) {
    // REVIEW: https://www.barrykooij.com/polyfilling-fetch-promises/
    fetch('/', {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: encode({ 'disabled-form-name': 'contact', ...this.state })
    })
      .then(() => {
        this.showMessage()
      })
      .catch((error) => {
        this.showMessage(error)
      })

    e.preventDefault()
  }

  handleChange (e) {
    this.setState({ [e.target.name]: e.target.value })
  }

  showMessage (error) {
    if (error) {
      this.setState({
        ...this.state,
        error: true
      })
    }

    this.setState({
      ...this.state,
      showMessage: true
    })
  }

  render () {
    const { name, email, comments } = this.state
    return (
      <div className={styles.wrap}>
        <div
          style={{
            display: this.state.showMessage ? 'none' : 'block'
          }}
        >
          <form method='post' onSubmit={this.handleSubmit}>
            <input type='hidden' name='disabled-form-name' value='contact' />
            <p style={{display: 'none'}}><label><input name='bot-field' /></label></p>
            <h2 className={styles.title}>
              <span>Purchase</span>
              {this.props.title}
            </h2>
            <p className={styles.intro}>{data.intro}</p>
            <p className={styles.field}>
              <label>
                Your name:
                <input type='text' name='name' value={name} onChange={this.handleChange} required />
              </label>
            </p>
            <p className={styles.field}>
              <label>
                Your email:
                <input type='email' name='email' value={email} onChange={this.handleChange} required />
              </label>
            </p>
            <p className={styles.field}>
              <label>
                Comments:
                <textarea name='comments' value={comments} onChange={this.handleChange} required />
              </label>
            </p>
            <p className={styles.submit}>
              <button type='submit'>{data.buttonText}</button>
            </p>
          </form>
        </div>
        <div
          style={{
            display: this.state.showMessage ? 'block' : 'none'
          }}
        >
          <PurchaseSuccess
            title={this.props.title}
            name={this.state.name}
            email={this.state.email}
            error={this.state.error}
          />
        </div>
      </div>
    )
  }
}

PurchaseForm.propTypes = {
  title: PropTypes.string.isRequired
}

export default PurchaseForm



