import React, { Component } from 'react'
import PropTypes from 'prop-types'
import ReactModal from 'react-modal'
import PurchaseForm from '../PurchaseForm/PurchaseForm'
import styles from './Purchase.module.scss'
import data from './Purchase.json'

class Purchase extends Component {
  constructor (props) {
    super(props)
    this.state = {
      showModal: false
    }
    this.openModal = this.openModal.bind(this)
    this.closeModal = this.closeModal.bind(this)
  }

  openModal () {
    this.setState({
      showModal: true
    })
  }

  closeModal () {
    this.setState({
      showModal: false
    })
  }

  render () {
    let price = null
    if (this.props.price) {
      price = (
        <div className={styles.price}>{this.props.price.toFixed(2)} (eur.)</div>
      )
    }
    return (
      <div className={styles.wrap}>
        <p>{data.label}</p>
        {price}
        <button type='button' className={styles.button} onClick={this.openModal}>
          <span></span>
        </button>
        <ReactModal
          isOpen={this.state.showModal}
          contentLabel={`${this.props.title}`}
          className={styles.modal}
          overlayClassName={styles.overlay}
          onRequestClose={this.closeModal}
          ariaHideApp={false}
        >
          <button type='button' className={styles.close} onClick={this.closeModal}>Close</button>
          <PurchaseForm
            title={this.props.title}
            price={this.props.price}
          />
        </ReactModal>
      </div>
    )
  }
}

// ReactModal.setAppElement('#___gatsby')

Purchase.propTypes = {
  title: PropTypes.string.isRequired,
  price: PropTypes.number
}

export default Purchase



