import React, { Component } from 'react'
import PropTypes from 'prop-types'
import { Link } from 'react-scroll'
import styles from './Nav.module.scss'

const pad = (num, size) => {
  const s = '0' + num
  return s.substr(s.length - size)
}

class Nav extends Component {
  constructor (props) {
    super(props)
    this.state = {
      showDropdown: false
    }
    this.toggleDropdown = this.toggleDropdown.bind(this)
  }

  toggleDropdown () {
    if (this.state.showDropdown) {
      this.setState({
        showDropdown: false
      })
    } else {
      this.setState({
        showDropdown: true
      })
    }
  }

  render () {
    const buttonText = this.state.showDropdown ? 'Hide index' : 'View index'
    const modifier = this.state.showDropdown ? styles.visible : styles.hidden
    return (
      <div className={styles.wrap}>
        <button className={styles.button} onClick={this.toggleDropdown} type='button'>
          <span>{buttonText}</span>
        </button>
        <div className={`${styles.dropdown} ${modifier}`}>
          <div className={styles.label}>(index)</div>
          <nav>
            <ul className={styles.list}>
              {this.props.items.map((item, i) => {
                const id = item.slug
                return (
                  <li className={styles.item} key={i}>
                    <Link to={id} activeClass={styles.active} spy smooth hashSpy offset={-30}>
                      <div className={styles.grid}>
                        <div className={styles.number}>{pad(i + 1)}.</div>
                        <div className={styles.info}>
                          <div className={styles.title}>
                            <span>{item.title}</span>
                          </div>
                        </div>
                      </div>
                    </Link>
                  </li>
                )
              })}
            </ul>
          </nav>
        </div>
      </div>
    )
  }
}

Nav.propTypes = {
  items: PropTypes.array.isRequired
}

export default Nav



